import{c as a,Q as o,j as e,m as r}from"./chunks/framework.DpF7k2f3.js";const q=JSON.parse('{"title":"제2장 왜 \\"먼저 들어가\\"가 합리적인 전략인가","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part1-cognition/chapter2.md","filePath":"ko/part1-cognition/chapter2.md","lastUpdated":1779671667000}'),n={name:"ko/part1-cognition/chapter2.md"};function p(i,t,u,l,s,c){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="제2장-왜-먼저-들어가-가-합리적인-전략인가" tabindex="-1">제2장 왜 &quot;먼저 들어가&quot;가 합리적인 전략인가 <a class="header-anchor" href="#제2장-왜-먼저-들어가-가-합리적인-전략인가" aria-label="Permalink to &quot;제2장 왜 &quot;먼저 들어가&quot;가 합리적인 전략인가&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>이전 챕터를 읽고 나면, AI 앱 개발이 생각처럼 높지 않은 것임을 알게 되었습니다. 하지만 아직도 주저하고 계실 겁니다 - &quot;장벽이 생각보다 높지 않다는 건 알겠는데, 아직 준비가 됐다고 느끼지 못한다.&quot;</p><p>이는 정상적입니다. &quot;준비&quot;这件事上一拖就是半年一年 많은 사람들을 보았습니다, 준비가 됐다고 느낄 때쯤이면, 기회 창은早已关闭了.</p><p>이 챕터에서 명확히 설명드리겠습니다: <strong>AI 앱 개발에서 &quot;먼저 들어가&quot;는 도박이 아니라 가장 효율적인 합리적 전략입니다.</strong></p><p>구체적으로 이해하게 될 것들:</p><ul><li>AI 기술의スキル半衰期가 얼마나 짧은지, 준비가 됐을 때黄花菜都已凉</li><li>기업이 정말 원하는 것이 &quot;전부 다 아는 사람&quot;이 아니라 &quot;일을 할 수 있는 사람&quot;인 이유 -，边干边学의 효율이 闭门苦读의 2-3배인 이유</li><li>&quot;나는 자격이 없다&quot;는这种感觉가 환상임을 이해하고 그것과和平共处하는 방법</li></ul><hr><h2 id="_2-1-ai-앱-개발의-스킬半衰期は驚くほど短い" tabindex="-1">2.1 AI 앱 개발의 스킬半衰期は驚くほど短い <a class="header-anchor" href="#_2-1-ai-앱-개발의-스킬半衰期は驚くほど短い" aria-label="Permalink to &quot;2.1 AI 앱 개발의 스킬半衰期は驚くほど短い&quot;">​</a></h2><p>먼저 제가 직접 목격한 사실을 말씀드리겠습니다.</p><p>2022년 10월, LangChain刚发布的时候, 제 친구는まるまる 3개월을 투자하여 이 프레임워크를 마스터하고十几개 데모를 만들었습니다, 이력서에는 똑똑히 적혀 있었습니다: &quot;LangChain 마스터&quot;. 2023년初 그는 이것으로 직장을 옮겨 급여가 40% 상승했습니다.</p><p>그런데呢? 2024년, LangChain 팀은 완전 다른 아키텍처의 LangGraph를 출시했습니다. 2025년 10월, LangChain은 1.0 버전을 출시하여 전체 프레임워크를 0부터 다시 썼습니다. 어떻게 될 것 같습니까? 그가 3개월 동안 배운 것의 대부분이 바로 무효가 되었습니다.</p><p><strong>이것이 AI 앱 개발의 잔인한 현실입니다: 당신이 배우고 있는 것은, 아직 배우는 동안에도 이미过时할 수 있습니다.</strong></p><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter2.html">中文版阅读</a></p></blockquote>',15)])])}const _=a(n,[["render",p]]);export{q as __pageData,_ as default};
